  ('aboriginal-57f41407-moex-00538', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '刑事訴訟法規定原則禁止夜間搜索，關於合法夜間搜索之敘述，下列何者正確？', '["警員持搜索票至犯罪嫌疑人之住居所執行，雖未經同意，亦可於夜間為之", "警員持搜索票至犯罪嫌疑人經營但已休息之飲料店執行，雖未經同意，亦可於夜間為之", "警員持搜索票至假釋人之友人房屋執行，雖未經屋主同意，亦可於夜間為之", "警員持搜索票至假釋人之住居所執行，雖未經同意，亦可於夜間為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
